package com.cho2hand.marketplace.controller.report;import com.cho2hand.marketplace.dto.report.CreateListingReportRequest;import com.cho2hand.marketplace.service.report.ReportService;import jakarta.validation.Valid;import jakarta.validation.constraints.Positive;import org.springframework.http.HttpStatus;import org.springframework.security.core.annotation.AuthenticationPrincipal;import org.springframework.web.bind.annotation.*;
@RestController@RequestMapping("/api/v1/listings/{listingId}/reports")public class ReportController{private final ReportService service;public ReportController(ReportService s){service=s;}@PostMapping@ResponseStatus(HttpStatus.CREATED)public void report(@AuthenticationPrincipal Long user,@PathVariable@Positive Long listingId,@Valid@RequestBody CreateListingReportRequest request){service.reportListing(user,listingId,request);}}
